"use strict";

class GestorRutasTuristicas {
    constructor() {
        this.rutas = [];
        this.mapasPendientes = [];
        this.contenedor = document.querySelector("main > section");
    }

    iniciar() {
        if (!this.contenedor) {
            return;
        }

        this.mostrarMensaje("Cargando rutas...");
        this.cargarDatosXML();
    }

    async cargarDatosXML() {
        try {
            const respuesta = await fetch("xml/rutas.xml", { cache: "no-store" });
            if (!respuesta.ok) {
                throw new Error("No se pudo recuperar rutas.xml.");
            }

            const texto = await respuesta.text();
            const xml = new DOMParser().parseFromString(texto, "application/xml");
            if (xml.querySelector("parsererror")) {
                throw new Error("XML inválido.");
            }

            this.procesarXML(xml);
        } catch (error) {
            this.mostrarMensaje("Error crítico: No se pudo cargar el archivo rutas.xml.");
        }
    }

    procesarXML(xml) {
        this.rutas = [];
        this.mapasPendientes = [];
        this.limpiarContenedor();

        const rutasXML = Array.from(xml.getElementsByTagName("ruta"));
        rutasXML.forEach((rutaNodo) => {
            const ruta = this.convertirRuta(rutaNodo);
            this.rutas.push(ruta);
            this.construirArticulo(ruta);
        });

        this.cargarGoogleMapsAPI();
    }

    convertirRuta(rutaXML) {
        const ruta = {
            nombre: this.textoDe(rutaXML, "nombre"),
            tipo: this.textoDe(rutaXML, "tipo"),
            medio: this.textoDe(rutaXML, "transporte"),
            duracion: this.textoDe(rutaXML, "duracion"),
            descripcion: this.textoDe(rutaXML, "descripcion"),
            kml: this.textoDe(rutaXML, "planimetria"),
            svg: this.textoDe(rutaXML, "altimetria"),
            hitos: [],
            referencias: []
        };

        const inicio = rutaXML.querySelector("coordenada");
        ruta.inicio = {
            lat: this.numeroDe(inicio, "latitud"),
            lng: this.numeroDe(inicio, "longitud")
        };

        const referencias = rutaXML.querySelectorAll("referencias > referencia");
        referencias.forEach((referencia) => {
            ruta.referencias.push(referencia.textContent.trim());
        });

        const hitos = Array.from(rutaXML.querySelectorAll("hitos > hito"));
        hitos.forEach((hitoNodo) => {
            const coordenada = hitoNodo.querySelector("coordenada");
            const distanciaAnterior = hitoNodo.querySelector("distanciaAnterior");
            const fotos = Array.from(hitoNodo.querySelectorAll("galeriaFotos > foto")).map((foto) => foto.textContent.trim());

            ruta.hitos.push({
                nombre: this.textoDe(hitoNodo, "nombreHito"),
                descripcion: this.textoDe(hitoNodo, "descripcionHito"),
                distancia: `${this.textoNodo(distanciaAnterior)} ${distanciaAnterior ? distanciaAnterior.getAttribute("unidades") || "" : ""}`.trim(),
                lat: this.numeroDe(coordenada, "latitud"),
                lng: this.numeroDe(coordenada, "longitud"),
                fotos
            });
        });

        return ruta;
    }

    construirArticulo(ruta) {
        const articulo = document.createElement("article");

        const h3 = document.createElement("h3");
        h3.textContent = ruta.nombre;
        articulo.appendChild(h3);

        const descripcion = document.createElement("p");
        descripcion.textContent = ruta.descripcion;
        articulo.appendChild(descripcion);

        const lista = document.createElement("ul");
        [
            `Tipo de ruta: ${ruta.tipo}`,
            `Transporte: ${ruta.medio}`,
            `Duración: ${ruta.duracion}`
        ].forEach((texto) => {
            const li = document.createElement("li");
            li.textContent = texto;
            lista.appendChild(li);
        });
        articulo.appendChild(lista);

        const h4Hitos = document.createElement("h4");
        h4Hitos.textContent = "Puntos de interés (Hitos)";
        articulo.appendChild(h4Hitos);

        const listaHitos = document.createElement("ol");
        ruta.hitos.forEach((hito) => {
            const item = document.createElement("li");

            const nombre = document.createElement("strong");
            nombre.textContent = hito.nombre;
            item.appendChild(nombre);

            item.appendChild(document.createTextNode(`: ${hito.descripcion}. `));

            const distancia = document.createElement("em");
            distancia.textContent = `(Distancia: ${hito.distancia})`;
            item.appendChild(distancia);

            if (hito.fotos.length > 0) {
                const salto = document.createElement("br");
                item.appendChild(salto);

                const imagen = document.createElement("img");
                imagen.src = `multimedia/${hito.fotos[0]}`;
                imagen.alt = `Foto de ${hito.nombre}`;
                item.appendChild(imagen);
            }

            listaHitos.appendChild(item);
        });
        articulo.appendChild(listaHitos);

        const h4Mapa = document.createElement("h4");
        h4Mapa.textContent = `Planimetría (${ruta.kml})`;
        articulo.appendChild(h4Mapa);

        const contenedorMapa = document.createElement("figure");
        contenedorMapa.setAttribute("role", "application");
        contenedorMapa.setAttribute("aria-label", `Mapa de la ruta ${ruta.nombre}`);
        contenedorMapa.tabIndex = 0;
        articulo.appendChild(contenedorMapa);

        const h4Svg = document.createElement("h4");
        h4Svg.textContent = `Altimetría (${ruta.svg})`;
        articulo.appendChild(h4Svg);

        const contenedorSvg = document.createElement("figure");
        articulo.appendChild(contenedorSvg);

        this.contenedor.appendChild(articulo);

        this.mapasPendientes.push({ ruta, nodo: contenedorMapa });
        this.cargarSvg(ruta.svg, contenedorSvg);
    }

    cargarGoogleMapsAPI() {
        if (!this.hayGoogleMaps()) {
            return;
        }

        window.initGoogleMaps = this.renderizarMapasPendientes.bind(this);

        if (window.google && window.google.maps) {
            window.initGoogleMaps();
            return;
        }

        const apiKey = window.GOOGLE_MAPS_API_KEY;
        if (!apiKey) {
            this.mostrarMensaje("No se detectó ninguna Google Maps API Key en window.GOOGLE_MAPS_API_KEY.");
            return;
        }

        const script = document.createElement("script");
        script.src = `https://maps.googleapis.com/maps/api/js?key=${encodeURIComponent(apiKey)}&callback=initGoogleMaps`;
        script.async = true;
        script.defer = true;
        script.onerror = this.mostrarMensaje.bind(this, "No se pudo cargar la librería de Google Maps.");
        document.head.appendChild(script);
    }

    renderizarMapasPendientes() {
        this.mapasPendientes.forEach((item) => {
            this.renderizarMapaGoogle(item.ruta, item.nodo);
        });
        this.mapasPendientes = [];
    }

    renderizarMapaGoogle(ruta, nodoDOMMapa) {
        const centro = {
            lat: ruta.inicio.lat,
            lng: ruta.inicio.lng
        };

        const mapa = new google.maps.Map(nodoDOMMapa, {
            zoom: 14,
            center: centro,
            mapTypeId: "terrain"
        });

        new google.maps.Marker({
            position: centro,
            map: mapa,
            title: `Inicio: ${ruta.nombre}`
        });

        ruta.hitos.forEach((hito) => {
            if (!Number.isNaN(hito.lat) && !Number.isNaN(hito.lng)) {
                new google.maps.Marker({
                    position: { lat: hito.lat, lng: hito.lng },
                    map: mapa,
                    title: hito.nombre
                });
            }
        });

        this.cargarTrazadoKML(ruta.kml).then((trazado) => {
            if (trazado.length === 0) {
                return;
            }

            const bounds = new google.maps.LatLngBounds();
            trazado.forEach((punto) => bounds.extend(punto));

            const linea = new google.maps.Polyline({
                path: trazado,
                geodesic: true,
                strokeColor: "#d60000",
                strokeOpacity: 0.8,
                strokeWeight: 5
            });

            linea.setMap(mapa);
            mapa.fitBounds(bounds);

            google.maps.event.addListenerOnce(mapa, "idle", () => {
                google.maps.event.trigger(mapa, "resize");
                if (trazado.length > 0) {
                    mapa.setCenter(trazado[0]);
                }
            });
        });
    }

    async cargarTrazadoKML(archivoKml) {
        try {
            const respuesta = await fetch(`xml/${archivoKml}`, { cache: "no-store" });
            if (!respuesta.ok) {
                return [];
            }

            const texto = await respuesta.text();
            const xml = new DOMParser().parseFromString(texto, "application/xml");
            const nodosCoords = xml.getElementsByTagNameNS("*", "coordinates");
            const coordenadas = nodosCoords.length > 0 ? nodosCoords[0] : xml.getElementsByTagName("coordinates")[0];

            if (!coordenadas || !coordenadas.textContent) {
                return [];
            }

            return coordenadas.textContent.trim().split(/\s+/).reduce((acumulado, par) => {
                const partes = par.split(",");
                if (partes.length >= 2) {
                    acumulado.push({
                        lat: parseFloat(partes[1]),
                        lng: parseFloat(partes[0])
                    });
                }
                return acumulado;
            }, []);
        } catch (error) {
            return [];
        }
    }

    async cargarSvg(archivoSvg, contenedorSvg) {
        try {
            const respuesta = await fetch(`xml/${archivoSvg}`, { cache: "no-store" });
            if (!respuesta.ok) {
                contenedorSvg.textContent = "No se encontró el archivo de altimetría.";
                return;
            }

            contenedorSvg.innerHTML = await respuesta.text();
        } catch (error) {
            contenedorSvg.textContent = "No se encontró el archivo de altimetría.";
        }
    }

    limpiarContenedor() {
        while (this.contenedor.firstChild) {
            this.contenedor.removeChild(this.contenedor.firstChild);
        }
    }

    mostrarMensaje(texto) {
        this.limpiarContenedor();
        const parrafo = document.createElement("p");
        parrafo.textContent = texto;
        this.contenedor.appendChild(parrafo);
    }

    textoDe(nodo, selector) {
        const elemento = nodo ? nodo.querySelector(selector) : null;
        return elemento ? elemento.textContent.trim() : "";
    }

    textoNodo(nodo) {
        return nodo && nodo.textContent ? nodo.textContent.trim() : "";
    }

    numeroDe(nodo, selector) {
        const valor = this.textoDe(nodo, selector);
        return valor === "" ? NaN : parseFloat(valor);
    }

    hayGoogleMaps() {
        return typeof window !== "undefined";
    }
}

document.addEventListener("DOMContentLoaded", new GestorRutasTuristicas().iniciar.bind(new GestorRutasTuristicas()));

